// ============================================================
// 급수별 × 종목별 문제 풀 구성 함수 (최종)
// [공통] 4급: L4(50) + TERMS(58) + EXTRA(10) → 랜덤 15문항
// [body]     3급: L3+L2+TERMS+EXTRA / 2급: L2+L3+TERMS+EXTRA / 1급: L1+TERMS+EXTRA
// [standing] 3급: S_L3+S_L2+TERMS+EXTRA / 2급: S_L2+S_L3+TERMS+EXTRA / 1급: S_L1+TERMS+EXTRA
// [wake]     3급: W_L3+W_L2+TERMS+EXTRA / 2급: W_L2+W_L3+TERMS+EXTRA / 1급: W_L1+TERMS+EXTRA
// [wave]     3급: V_L3+TERMS+EXTRA / 2급: V_L2+V_L3+TERMS+EXTRA / 1급: V_L1+TERMS+EXTRA
// ============================================================
function getQuestionBank(discipline, level) {
  const disc = discipline || 'body';

  if (disc === 'standing') {
    switch(level) {
      case 4: return [...QUESTIONS_BODY_L4, ...QUESTIONS_TERMS, ...QUESTIONS_EXTRA];
      case 3: return [...QUESTIONS_STANDING_L3, ...QUESTIONS_STANDING_L2, ...QUESTIONS_TERMS, ...QUESTIONS_EXTRA];
      case 2: return [...QUESTIONS_STANDING_L2, ...QUESTIONS_STANDING_L3, ...QUESTIONS_TERMS, ...QUESTIONS_EXTRA];
      case 1: return [...QUESTIONS_STANDING_L1, ...QUESTIONS_TERMS, ...QUESTIONS_EXTRA];
      default: return [...QUESTIONS_BODY_L4, ...QUESTIONS_TERMS];
    }
  }

  if (disc === 'wake') {
    switch(level) {
      case 4: return [...QUESTIONS_BODY_L4, ...QUESTIONS_TERMS, ...QUESTIONS_EXTRA];
      case 3: return [...QUESTIONS_WAKE_L3, ...QUESTIONS_WAKE_L2, ...QUESTIONS_TERMS, ...QUESTIONS_EXTRA];
      case 2: return [...QUESTIONS_WAKE_L2, ...QUESTIONS_WAKE_L3, ...QUESTIONS_TERMS, ...QUESTIONS_EXTRA];
      case 1: return [...QUESTIONS_WAKE_L1, ...QUESTIONS_TERMS, ...QUESTIONS_EXTRA];
      default: return [...QUESTIONS_BODY_L4, ...QUESTIONS_TERMS];
    }
  }

  if (disc === 'wave') {
    switch(level) {
      case 4: return [...QUESTIONS_BODY_L4, ...QUESTIONS_TERMS, ...QUESTIONS_EXTRA];
      case 3: return [...QUESTIONS_WAVE_L3, ...QUESTIONS_TERMS, ...QUESTIONS_EXTRA];
      case 2: return [...QUESTIONS_WAVE_L2, ...QUESTIONS_WAVE_L3, ...QUESTIONS_TERMS, ...QUESTIONS_EXTRA];
      case 1: return [...QUESTIONS_WAVE_L1, ...QUESTIONS_TERMS, ...QUESTIONS_EXTRA];
      default: return [...QUESTIONS_BODY_L4, ...QUESTIONS_TERMS];
    }
  }

  // body (fallback)
  switch(level) {
    case 4: return [...QUESTIONS_BODY_L4, ...QUESTIONS_TERMS, ...QUESTIONS_EXTRA];
    case 3: return [...QUESTIONS_BODY_L3, ...QUESTIONS_BODY_L2, ...QUESTIONS_TERMS, ...QUESTIONS_EXTRA];
    case 2: return [...QUESTIONS_BODY_L2, ...QUESTIONS_BODY_L3, ...QUESTIONS_TERMS, ...QUESTIONS_EXTRA];
    case 1: return [...QUESTIONS_BODY_L1, ...QUESTIONS_TERMS, ...QUESTIONS_EXTRA];
    default: return [...QUESTIONS_BODY_L4, ...QUESTIONS_TERMS];
  }
}
